changeSet.sql:
DROP TABLE data_type_classifications_to_regulations;

CREATE TABLE regulations_to_data_type_classifications
(
    id serial,
	regulation_id integer DEFAULT NULL,
	data_type_classification_id integer NOT NULL,

    CONSTRAINT pk_regulations_to_data_type_classifications PRIMARY KEY (id)
	, CONSTRAINT fk_regulations_to_data_type_classifications_to_data_type_class FOREIGN KEY (data_type_classification_id) REFERENCES data_type_classifications (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_regulations_to_data_type_classifications_to_regulations FOREIGN KEY (regulation_id) REFERENCES regulations (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_regulations_to_data_type_classifications_data_type_class ON regulations_to_data_type_classifications (data_type_classification_id);
CREATE INDEX i_regulations_to_data_type_classifications_regulation ON regulations_to_data_type_classifications (regulation_id);

CREATE TABLE regulations_to_industries
(
    id serial,
	regulation_id integer DEFAULT NULL,
	industry_id integer NOT NULL,

    CONSTRAINT pk_regulations_to_industries PRIMARY KEY (id)
	, CONSTRAINT fk_regulations_to_industries_to_data_type_class FOREIGN KEY (industry_id) REFERENCES industries (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_regulations_to_industries_to_regulations FOREIGN KEY (regulation_id) REFERENCES regulations (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_regulations_to_industries_data_type_class ON regulations_to_industries (industry_id);
CREATE INDEX i_regulations_to_industries_regulation ON regulations_to_industries (regulation_id);

