	, CONSTRAINT fk_regulations_to_technologies_to_data_type_class FOREIGN KEY (technology_id) REFERENCES technologies (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_regulations_to_technologies_to_regulations FOREIGN KEY (regulation_id) REFERENCES regulations (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_regulations_to_technologies_data_type_class ON regulations_to_technologies (technology_id);
CREATE INDEX i_regulations_to_technologies_regulation ON regulations_to_technologies (regulation_id);

CREATE TABLE regulations_to_countries
(
    id serial,
	regulation_id integer DEFAULT NULL,
	country_id integer NOT NULL,

    CONSTRAINT pk_regulations_to_countries PRIMARY KEY (id)
	, CONSTRAINT fk_regulations_to_countries_to_data_type_class FOREIGN KEY (country_id) REFERENCES countries (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_regulations_to_countries_to_regulations FOREIGN KEY (regulation_id) REFERENCES regulations (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_regulations_to_countries_data_type_class ON regulations_to_countries (country_id);
CREATE INDEX i_regulations_to_countries_regulation ON regulations_to_countries (regulation_id);

CREATE TABLE regulations_to_states
(
    id serial,
	regulation_id integer DEFAULT NULL,
	state_id integer NOT NULL,

    CONSTRAINT pk_regulations_to_states PRIMARY KEY (id)
	, CONSTRAINT fk_regulations_to_states_to_data_type_class FOREIGN KEY (state_id) REFERENCES states (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_regulations_to_states_to_regulations FOREIGN KEY (regulation_id) REFERENCES regulations (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_regulations_to_states_data_type_class ON regulations_to_states (state_id);
CREATE INDEX i_regulations_to_states_regulation ON regulations_to_states (regulation_id);

ALTER TABLE regulations ADD COLUMN is_data_type boolean DEFAULT false;
ALTER TABLE regulations ADD COLUMN is_industry boolean DEFAULT false;
ALTER TABLE regulations ADD COLUMN is_technology boolean DEFAULT false;
ALTER TABLE regulations ADD COLUMN is_geography boolean DEFAULT false;

rollback.sql:
DROP TABLE IF EXISTS regulations_to_data_type_classifications;
DROP TABLE IF EXISTS regulations_to_industries;
DROP TABLE IF EXISTS regulations_to_technologies;
